#include<bits/stdc++.h>
using namespace std;
int n,m,k,col[110],ans=INT_MAX,dp[110][(1<<14)];
vector<pair<int,int>> mp[110];
void dfs(int x,int cnt,int s,int sum)
{
    if(s&(1<<col[x]))
    {
        return;
    }
    if(sum>=ans||sum>=dp[x][s])
    {
        return;
    }
    if(cnt==k)
    {
        ans=sum;
        return;
    }
    dp[x][s]=sum;
    for(auto i:mp[x])
    {
        int v=i.first,val=i.second;
        dfs(v,cnt+1,s|(1<<col[x]),sum+val);
    }
}
int main()
{
    scanf("%d%d%d",&n,&m,&k);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&col[i]);
    }
    for(int i=1;i<=m;i++)
    {
        int u,v,w;
        scanf("%d%d%d",&u,&v,&w);
        mp[u].push_back(make_pair(v,w));
    }
    memset(dp,0x3f,sizeof(dp));
    for(int i=1;i<=n;i++)
    {
        dp[i][(1<<col[i])]=0;
    }
    for(int i=1;i<=n;i++)
    {
        dfs(i,1,0,0);
    }
    if(ans>1e9)
    {
        printf("Ushio!");
        return 0;
    }
    printf("%d",ans);
    return 0;
}
